1635	    if (!state.looks[brandId]) state.looks[brandId] = [];
1636	    state.looks[brandId].push({id:uid(),location:null,models:[],outfits:[],priority:0,notes:''});
1637	    activeLookTabs[brandId] = state.looks[brandId].length - 1;
1638	    saveState(); refreshBrandPanel(brandId); switchTab(brandId);
1639	  });
1640	
1641	  // Remove last look
1642	  panel.querySelector('[data-remove-look]')?.addEventListener('click', () => {
1643	    if (!state.looks[brandId] || state.looks[brandId].length <= 1) return;
1644	    state.looks[brandId].pop();
1645	    activeLookTabs[brandId] = Math.min(activeLookTabs[brandId]||0, state.looks[brandId].length-1);
1646	    saveState(); refreshBrandPanel(brandId); switchTab(brandId);
1647	  });
1648	
1649	  // Asset assign/toggle
1650	  panel.querySelectorAll('[data-assign-asset]').forEach(wrap => {
1651	    wrap.addEventListener('click', () => {
1652	      const assetId = wrap.dataset.assignAsset;
1653	      const type    = wrap.dataset.assignType;
1654	      const lookId  = wrap.dataset.look;
1655	      const bId     = wrap.dataset.brand;
1656	      const look    = state.looks[bId]?.find(l => l.id === lookId);
1657	      if (!look) return;
1658	      if (type === 'location') {
1659	        look.location = look.location === assetId ? null : assetId;
1660	      } else if (type === 'models') {
1661	        look.models = look.models.includes(assetId) ? look.models.filter(id=>id!==assetId) : [...look.models, assetId];
1662	      } else {
