function wireLookEditor(panel, brandId) {
  // Tab switching
  panel.querySelectorAll('.look-tab-btn').forEach((tab, idx) => {
    tab.addEventListener('click', () => {
      activeLookTabs[brandId] = idx;
      panel.querySelectorAll('.look-tab-btn').forEach(t => t.classList.toggle('active', t===tab));
      panel.querySelectorAll('.look-panel').forEach((p,i) => p.classList.toggle('active', i===idx));
    });
  });

  // Add look
  panel.querySelector('[data-add-look]')?.addEventListener('click', () => {
    if (!state.looks[brandId]) state.looks[brandId] = [];
    state.looks[brandId].push({id:uid(),location:null,models:[],outfits:[],priority:0,notes:''});
    activeLookTabs[brandId] = state.looks[brandId].length - 1;
    saveState(); refreshBrandPanel(brandId); switchTab(brandId);
  });

  // Remove last look
  panel.querySelector('[data-remove-look]')?.addEventListener('click', () => {
    if (!state.looks[brandId] || state.looks[brandId].length <= 1) return;
    state.looks[brandId].pop();
    activeLookTabs[brandId] = Math.min(activeLookTabs[brandId]||0, state.looks[brandId].length-1);
    saveState(); refreshBrandPanel(brandId); switchTab(brandId);
  });

  // Asset assign/toggle
  panel.querySelectorAll('[data-assign-asset]').forEach(wrap => {
    wrap.addEventListener('click', () => {
      const assetId = wrap.dataset.assignAsset;
      const type    = wrap.dataset.assignType;
      const lookId  = wrap.dataset.look;
      const bId     = wrap.dataset.brand;
      const look    = state.looks[bId]?.find(l => l.id === lookId);
      if (!look) return;
      if (type === 'location') {
        look.location = look.location === assetId ? null : assetId;
      } else if (type === 'models') {
        look.models = look.models.includes(assetId) ? look.models.filter(id=>id!==assetId) : [...look.models, assetId];
      } else {
        look.outfits = look.outfits.includes(assetId) ? look.outfits.filter(id=>id!==assetId) : [...look.outfits, assetId];
      }
      saveState(); refreshBrandPanel(bId); switchTab(bId);
    });
  });

  // Clear picks
  panel.querySelectorAll('[data-clear-pick]').forEach(btn => {
    btn.addEventListener('click', () => {
      const type   = btn.dataset.clearPick;
      const lookId = btn.dataset.look;
      const bId    = btn.dataset.brand;
      const look   = state.looks[bId]?.find(l => l.id === lookId);
      if (!look) return;
      if      (type==='location') look.location = null;
      else if (type==='models')   look.models   = [];
      else                        look.outfits  = [];
      saveState(); refreshBrandPanel(bId); switchTab(bId);
    });
  });

  // Star ratings
  panel.querySelectorAll('.star[data-star]').forEach(star => {
    star.addEventListener('click', e => {
      e.stopPropagation();
      const val    = parseInt(star.dataset.star, 10);
      const lookId = star.dataset.look;
      const bId    = star.dataset.brand;
      const look   = state.looks[bId]?.find(l => l.id === lookId);
      if (!look) return;
      look.priority = look.priority === val ? 0 : val;
      saveState();
      panel.querySelectorAll(`.star[data-look="${lookId}"]`).forEach(s =>
        s.classList.toggle('filled', parseInt(s.dataset.star,10) <= look.priority)
      );
    });
  });

  // Notes
  panel.querySelectorAll('.look-notes').forEach(ta => {
    let timer;
    ta.addEventListener('input', () => {
      clearTimeout(timer);
      timer = setTimeout(() => {
        const look = state.looks[ta.dataset.noteBrand]?.find(l => l.id === ta.dataset.noteLook);
        if (look) { look.notes = ta.value; saveState(); }
      }, 600);
    });
  });

  // Compile mood board
  panel.querySelectorAll('[data-compile-look]').forEach(btn => {
    btn.addEventListener('click', () => compileMoodBoard(btn.dataset.compileBrand, btn.dataset.compileLook));
  });
}

// ── LEGACY (unused, kept for reference) ────────────────────────────
function buildLooksHtml(brandId, looks) {
  return looks.map((look, i) => {
    const loc     = look.location ? getAsset(look.location) : null;
    const models  = (look.models||[]).map(id => getAsset(id)).filter(Boolean);
    const outfits = (look.outfits||[]).map(id => getAsset(id)).filter(Boolean);

    const locSlot = `
      <div class="look-slot look-slot-location" data-pick="location" data-look="${look.id}" data-brand="${brandId}">
        <span class="slot-type-pill">Location</span>
        ${loc
          ? `<img src="${loc.src}" alt="${loc.name}"${loc.rotation ? ` class="rot-${loc.rotation}"` : ''}>
             <button class="look-slot-remove" data-clear-slot="location" data-look="${look.id}" data-brand="${brandId}">&times;</button>`
          : `<div class="look-slot-inner">
               <div class="slot-icon">&#x25A2;</div>
               <span class="slot-empty-label">Add location</span>
             </div>`
        }
      </div>`;

    const modelContent = models.length
      ? `<div class="model-strip">${models.map(m => `<img src="${m.src}" alt="${m.name}"${m.rotation ? ` class="rot-${m.rotation}"` : ''}>`).join('')}</div>
         <button class="look-slot-remove" data-clear-slot="model" data-look="${look.id}" data-brand="${brandId}">&times;</button>`
      : `<div class="look-slot-inner">
           <div class="slot-icon">&#x25CB;</div>
           <span class="slot-empty-label">Add model</span>
         </div>`;

    const modelSlot = `
      <div class="look-slot" data-pick="model" data-look="${look.id}" data-brand="${brandId}">
        <span class="slot-type-pill">Model${models.length>1?'s':''}</span>
        ${modelContent}
      </div>`;

    const outfitContent = outfits.length
      ? `<div class="model-strip">${outfits.map(o => `<img src="${o.src}" alt="${o.name}"${o.rotation ? ` class="rot-${o.rotation}"` : ''}>`).join('')}</div>
         <button class="look-slot-remove" data-clear-slot="outfit" data-look="${look.id}" data-brand="${brandId}">&times;</button>`
      : `<div class="look-slot-inner">
           <div class="slot-icon">&#x25B3;</div>
           <span class="slot-empty-label">Add outfit</span>
         </div>`;

    const outfitSlot = `
      <div class="look-slot" data-pick="outfit" data-look="${look.id}" data-brand="${brandId}">
        <span class="slot-type-pill">Outfit${outfits.length>1?'s':''}</span>
        ${outfitContent}
      </div>`;

    const priority = look.priority || 0;
    const stars = [1,2,3,4,5].map(n =>
      `<span class="star${priority>=n?' filled':''}" data-star="${n}" data-look="${look.id}" data-brand="${brandId}">&#9733;</span>`
    ).join('');

    return `
      <div class="look-card">
        <div class="look-card-header">
          <div class="look-num-editorial">
            <span class="look-num-label">Look</span>
            <span class="look-num-val">${String(i+1).padStart(2,'0')}</span>
          </div>
          <div class="star-rating">${stars}</div>
          <span class="look-hint">Drag or click</span>
        </div>
        <div class="look-board">
          ${locSlot}
          ${modelSlot}
          ${outfitSlot}
        </div>
        <textarea class="look-notes" data-note-look="${look.id}" data-note-brand="${brandId}" placeholder="Look notes&hellip;">${look.notes||''}</textarea>
      </div>`;
  }).join('');
}

function wireLookSlots(panel, brandId) {
  panel.querySelectorAll('[data-pick]').forEach(slot => {
    // Click to open picker
    slot.addEventListener('click', e => {
      if (e.target.closest('[data-clear-slot]')) return;
      const pickType = slot.dataset.pick;
      const lookId   = slot.dataset.look;
      const poolType = pickType === 'location' ? 'locations' : pickType === 'model' ? 'models' : 'outfits';
      const available = getBrandAssetObjects(brandId, poolType);
      openPicker(
        `Select ${pickType.charAt(0).toUpperCase()+pickType.slice(1)}`,
        available,
        asset => {
          const look = state.looks[brandId].find(l => l.id === lookId);
          if (!look) return;
          if      (pickType === 'location') { look.location = asset.id; }
          else if (pickType === 'model')    { if (!look.models.includes(asset.id))  look.models.push(asset.id); }
          else                              { if (!look.outfits.includes(asset.id)) look.outfits.push(asset.id); }
          saveState();
          refreshBrandPanel(brandId);
          switchTab(brandId);
        }
      );
    });

    // Drag over / drop
    slot.addEventListener('dragover', e => { e.preventDefault(); slot.classList.add('drag-over'); });
    slot.addEventListener('dragleave', () => slot.classList.remove('drag-over'));
    slot.addEventListener('drop', e => {
      e.preventDefault();
      slot.classList.remove('drag-over');
      try {
        const data    = JSON.parse(e.dataTransfer.getData('text/plain'));
        const pickType = slot.dataset.pick;
        const expected = pickType; // 'location' | 'model' | 'outfit'
        if (data.type !== expected) { toast(`Drop a ${expected} here`); return; }
        const lookId = slot.dataset.look;
        const look   = state.looks[brandId].find(l => l.id === lookId);
        if (!look) return;
        if      (pickType === 'location') { look.location = data.id; }
        else if (pickType === 'model')    { if (!look.models.includes(data.id))  look.models.push(data.id); }
        else                              { if (!look.outfits.includes(data.id)) look.outfits.push(data.id); }
        saveState();
        refreshBrandPanel(brandId);
        switchTab(brandId);
      } catch(err) {}
    });
  });

  panel.querySelectorAll('[data-clear-slot]').forEach(btn => {
    btn.addEventListener('click', e => {
      e.stopPropagation();
      const slotType = btn.dataset.clearSlot;
      const lookId   = btn.dataset.look;
      const bId      = btn.dataset.brand;
      const look     = state.looks[bId].find(l => l.id === lookId);
      if (!look) return;
      if      (slotType === 'location') look.location = null;
      else if (slotType === 'model')    look.models   = [];
      else                              look.outfits  = [];
      saveState();
      refreshBrandPanel(bId);
      switchTab(bId);
    });
  });

  // Star rating
  panel.querySelectorAll('.star[data-star]').forEach(star => {
    star.addEventListener('click', e => {
      e.stopPropagation();
      const val    = parseInt(star.dataset.star, 10);
      const lookId = star.dataset.look;
      const bId    = star.dataset.brand;
      const look   = state.looks[bId].find(l => l.id === lookId);
      if (!look) return;
      look.priority = look.priority === val ? 0 : val; // click same star = clear
      saveState();
      refreshBrandPanel(bId);
      switchTab(bId);
    });
  });

  // Look notes — debounced save
  panel.querySelectorAll('.look-notes').forEach(ta => {
    let noteTimer;
    ta.addEventListener('input', () => {
      clearTimeout(noteTimer);
      noteTimer = setTimeout(() => {
        const lookId = ta.dataset.noteLook;
        const bId    = ta.dataset.noteBrand;
        const look   = state.looks[bId]?.find(l => l.id === lookId);
        if (look) { look.notes = ta.value; saveState(); }
      }, 500);
    });
  });
}

function setLookCount(brandId, n) {
  const brand = state.brands.find(b => b.id === brandId);
  if (!brand) return;
  brand.lookCount = n;
  const current = state.looks[brandId] || [];
  if (n > current.length) {
    for (let i = current.length; i < n; i++) current.push({ id: uid(), location:null, models:[], outfits:[] });
  } else {
    state.looks[brandId] = current.slice(0, n);
  }
  state.looks[brandId] = state.looks[brandId] || current;
  saveState();
  refreshBrandPanel(brandId);
  switchTab(brandId);
  toast(`${n} look${n===1?'':'s'} set`);
}

