function initState() {
  const saved = loadState();
  if (saved && saved.pool) {
    state = saved;
    if (!state.brands)      state.brands = [];
    if (!state.brandAssets) state.brandAssets = {};
    if (!state.looks)       state.looks = {};
    return;
  }
  function makeAsset(src, type) {
    const name = src.split('/').pop().replace(/\.[^.]+$/,'').replace(/_/g,' ');
    return { id: uid(), src, name, type };
  }
  state = {
    brands: [],
    pool: {
      models:    ASSET_PATHS.models.map(s => makeAsset(s,'model')),
      locations: ASSET_PATHS.locations.map(s => makeAsset(s,'location')),
      outfits:   ASSET_PATHS.outfits.map(s => makeAsset(s,'outfit')),
    },
    brandAssets: {},
    looks: {}
  };
  saveState();
}

// ── HELPERS ────────────────────────────────────────────────────────
function getAsset(id) {
  for (const type of ['models','locations','outfits']) {
    const a = state.pool[type].find(a => a.id === id);
    if (a) return a;
  }
  return null;
}
function getBrandAssets(brandId) {
  return state.brandAssets[brandId] || { models:[], locations:[], outfits:[] };
}
function getBrandAssetObjects(brandId, type) {
  const ids = getBrandAssets(brandId)[type] || [];
  return ids.map(id => getAsset(id)).filter(Boolean);
}
function getLooks(brandId) { return state.looks[brandId] || []; }
function sentBrandsForAsset(assetId) {
  return state.brands.filter(b => {
    const ba = state.brandAssets[b.id] || {};
    return Object.values(ba).some(arr => arr.includes(assetId));
  });
}

// ── TOAST ──────────────────────────────────────────────────────────
let toastTimer;
function toast(msg) {
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.classList.add('show');
  clearTimeout(toastTimer);
  toastTimer = setTimeout(() => t.classList.remove('show'), 2400);
}

// ── LOGIN ──────────────────────────────────────────────────────────

