  wireLookEditor(panel, brandId);

  // Brand notes save
  const brandNotesEl = document.getElementById(`brand-notes-${brandId}`);
  if (brandNotesEl) {
    let brandNoteTimer;
    brandNotesEl.addEventListener('input', () => {
      clearTimeout(brandNoteTimer);
      brandNoteTimer = setTimeout(() => {
        const b = state.brands.find(b => b.id === brandId);
        if (b) { b.notes = brandNotesEl.value; saveState(); }
      }, 600);
    });
  }

  // Drag from brand asset cards
  panel.querySelectorAll('.brand-asset-card[draggable]').forEach(card => {
    card.addEventListener('dragstart', e => {
      e.dataTransfer.setData('text/plain', JSON.stringify({id: card.dataset.dragId, type: card.dataset.dragType}));
      card.classList.add('dragging');
    });
    card.addEventListener('dragend', () => card.classList.remove('dragging'));
  });

  wireLookSlots(panel, brandId);
}

