${['models','locations','outfits'].map(type => `
<div class="pool-section">
  <div class="section-rule">
    <div class="section-rule-line"></div>
    <span class="section-title">${type.charAt(0).toUpperCase()+type.slice(1)}<span class="section-count"> &mdash; ${(ba[type]||[]).length}</span></span>
