${['models','locations','outfits'].map(type => {
  const rawIds = ba[type]||[];
  const assetIds = type === 'outfits'
    ? [...rawIds].sort((a,b) => ((state.outfitPriority?.[brandId]?.[b])||0) - ((state.outfitPriority?.[brandId]?.[a])||0))
    : rawIds;
  return `
<div class="pool-section">
  <div class="section-rule">
    <div class="section-rule-line"></div>
    <span class="section-title">${type.charAt(0).toUpperCase()+type.slice(1)}<span class="section-count"> &mdash; ${rawIds.length}</span></span>
    <div class="section-rule-line"></div>
  </div>
  ${assetIds.length === 0
    ? `<div class="empty-pool">No ${type} assigned yet &mdash; use &ldquo;Send to&rdquo; on assets in the Global Pool.</div>`
    : `<div class="brand-asset-grid">
        ${assetIds.map(assetId => {
          const a = getAsset(assetId);
          if (!a) return '';
          if (type === 'outfits') {
            const op = (state.outfitPriority?.[brandId]?.[assetId]) || 0;
            const ostars = [1,2,3,4,5].map(n =>
              `<span class="outfit-star${op>=n?' filled':''}" data-outfit-star="${n}" data-asset="${a.id}" data-brand="${brandId}">&#9733;</span>`
            ).join('');
            return `<div class="brand-asset-card${op>0?' has-rating':''}" data-lightbox="${a.src}" draggable="true" data-drag-id="${a.id}" data-drag-type="${a.type}">
              <img src="${a.src}" alt="${a.name}" loading="lazy">
              <div class="outfit-star-overlay">${ostars}</div>
              ${role==='admin' ? `<button class="brand-asset-remove" data-remove-from-brand="${assetId}" data-brand="${brandId}" data-type="${type}" title="Remove from brand">&times;</button>` : ''}
            </div>`;
          }
          return `<div class="brand-asset-card" data-lightbox="${a.src}" draggable="true" data-drag-id="${a.id}" data-drag-type="${a.type}">
            <img src="${a.src}" alt="${a.name}" loading="lazy">
            ${role==='admin' ? `<button class="brand-asset-remove" data-remove-from-brand="${assetId}" data-brand="${brandId}" data-type="${type}" title="Remove from brand">&times;</button>` : ''}
          </div>`;
        }).join('')}
       </div>`
  }
</div>`;
}).join('')}

