  position:absolute;bottom:0;left:0;right:0;
  display:flex;justify-content:center;gap:3px;padding:8px 4px 6px;
  background:linear-gradient(transparent,rgba(0,0,0,.72));
  opacity:0;transition:opacity .15s;pointer-events:none;
}
.brand-asset-card:hover .outfit-star-overlay,
.brand-asset-card.has-rating .outfit-star-overlay{opacity:1;pointer-events:auto}
.outfit-star{
  font-size:.85rem;cursor:pointer;color:rgba(255,255,255,.3);
  transition:color .1s;user-select:none;line-height:1;
}
.outfit-star.filled{color:var(--gold)}
.outfit-star:hover{color:var(--gold)}

