// ── SYNC FROM FIREBASE ─────────────────────────────────────────────
async function syncFromFirebase() {
  if (!db) { toast('Firebase not configured'); return; }
  const btn = document.getElementById('sync-btn');
  if (btn) { btn.textContent = 'Syncing…'; btn.disabled = true; }
  try {
    const snap = await db.ref('portal').get();
    if (snap.exists()) {
      state = snap.val();
      if (!state.brands)         state.brands = [];
      if (!state.brandAssets)    state.brandAssets = {};
      if (!state.looks)          state.looks = {};
      if (!state.outfitPriority) state.outfitPriority = {};
      try { localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); } catch(e){}
      renderGlobalPool();
      state.brands.forEach(b => renderBrandTab(b));
      switchTab(activeTab || 'main');
      toast('Synced — showing latest client selections');
    }
  } catch(e) { toast('Sync failed — check connection'); console.warn(e); }
  if (btn) { btn.textContent = 'Sync'; btn.disabled = false; }
}

// ── START APP ──────────────────────────────────────────────────────
async function startApp() {
  document.getElementById('login-screen').style.display = 'none';
  document.getElementById('app').style.display = 'block';
  document.getElementById('app-loading').style.display = 'flex';

  await initState();

  document.getElementById('app-loading').style.display = 'none';

  const badge = document.getElementById('role-badge');
  if (role === 'admin') {
    badge.textContent = 'Admin';
    badge.className   = 'role-badge';
    document.getElementById('add-brand-row').style.display    = 'flex';
    document.getElementById('admin-upload-strip').style.display = '';
    const syncBtn = document.getElementById('sync-btn');
    if (syncBtn) syncBtn.style.display = '';
  } else {
    badge.textContent = 'Client';
    badge.className   = 'role-badge client';
  }

  renderGlobalPool();
  state.brands.forEach(b => renderBrandTab(b));
  switchTab('main');
  const smBar = document.getElementById('select-mode-bar');
  if (smBar) smBar.classList.add('visible');
}

