async function loadState() {
  if (db) {
    try {
      const snap = await db.ref('portal').get();
      if (snap.exists()) {
        const val = snap.val();
        try { localStorage.setItem(STORAGE_KEY, JSON.stringify(val)); } catch(e){}
        return val;
      }
    } catch(e) { console.warn('Firebase load failed, falling back to localStorage', e); }
  }
  try { const r = localStorage.getItem(STORAGE_KEY); if (r) return JSON.parse(r); } catch(e){}
  return null;
}

input.new_string:
async function loadState() {
  let firebaseState = null;
  if (db) {
    try {
      const snap = await db.ref('portal').get();
      if (snap.exists()) firebaseState = snap.val();
    } catch(e) { console.warn('Firebase load failed, falling back to localStorage', e); }
  }
  let localState = null;
  try { const r = localStorage.getItem(STORAGE_KEY); if (r) localState = JSON.parse(r); } catch(e){}

  // Prefer whichever state has more brands (real data wins over blank slate)
  const fbBrands = (firebaseState?.brands || []).length;
  const lsBrands = (localState?.brands || []).length;
  if (firebaseState && fbBrands >= lsBrands) return { data: firebaseState, source: 'firebase' };
  if (localState) return { data: localState, source: 'localStorage' };
  return { data: null, source: 'none' };
}

