function toArr(v) {
  if (!v) return [];
  return Array.isArray(v) ? v : Object.values(v);
}
function normalizeState(s) {
  if (!s) return s;
  if (s.pool) {
    for (const t of ['models','locations','outfits']) {
      if (s.pool[t]) s.pool[t] = toArr(s.pool[t]);
    }
  }
  if (s.brands) s.brands = toArr(s.brands);
  if (s.brandAssets) {
    Object.keys(s.brandAssets).forEach(bid => {
      const ba = s.brandAssets[bid];
      if (ba) for (const t of ['models','locations','outfits']) {
        if (ba[t]) ba[t] = toArr(ba[t]);
      }
    });
  }
  if (s.looks) {
    Object.keys(s.looks).forEach(bid => {
      s.looks[bid] = toArr(s.looks[bid]);
      s.looks[bid].forEach(look => {
        if (look.models)  look.models  = toArr(look.models);
        if (look.outfits) look.outfits = toArr(look.outfits);
      });
    });
  }
  return s;
}

