  if (!s) return s;
  if (s.pool) {
    for (const t of ['models','locations','outfits']) {
      if (s.pool[t]) s.pool[t] = toArr(s.pool[t]);
    }
  }
  if (s.brands) s.brands = toArr(s.brands);
  if (s.brandAssets) {
