['models','locations','outfits'].forEach(type => {
  document.getElementById('upload-'+type).addEventListener('change', function() {
    const files = Array.from(this.files);
    files.forEach(file => {
      const reader = new FileReader();
      reader.onload = e => {
        const asset = { id: uid(), src: e.target.result, name: file.name.replace(/\.[^.]+$/,''), type };
        state.pool[type].push(asset);
        saveState();
        renderGlobalPool();
      };
      reader.readAsDataURL(file);
    });
    this.value = '';
    toast(`${files.length} image${files.length===1?'':'s'} added`);
  });
});

// ── BRAND PANEL ────────────────────────────────────────────────────
function renderBrandTab(brand) {
  if (!document.querySelector(`.tab-btn[data-tab="${brand.id}"]`)) {
    const addRow = document.getElementById('add-brand-row');
    const btn = document.createElement('button');
    btn.className = 'tab-btn brand-tab';
    btn.dataset.tab = brand.id;
    btn.textContent = brand.name;
    addRow.parentNode.insertBefore(btn, addRow);
  }
  if (!document.getElementById('panel-'+brand.id)) {
    const panel = document.createElement('div');
    panel.id = 'panel-'+brand.id;
    panel.className = 'tab-panel brand-page';
    panel.style.display = 'none';
    document.getElementById('tab-panels').appendChild(panel);
  }
  refreshBrandPanel(brand.id);
}

